INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (101, 1, 'Una obra maestra absoluta, aunque la dificultad puede ser frustrante al principio.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (102, 1, 'El mundo abierto es increíble, pero la optimización en PC necesita mejoras.', 4, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (103, 1, 'Demasiado difícil para mi gusto, no pude pasar del primer jefe.', 2, 'PENDIENTE');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (104, 2, 'La libertad de exploración no tiene precedentes. Un juego que define una generación.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (105, 2, 'Visualmente hermoso, aunque las armas se rompen demasiado rápido.', 4, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (101, 2, 'Una aventura épica de principio a fin, totalmente recomendado.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (106, 3, 'El mejor metroidvania que he jugado. La música y el arte son espectaculares.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (107, 3, 'Excelente diseño de niveles, pero el retroceso al morir es muy castigador.', 4, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (108, 3, 'Por el precio que tiene, ofrece una cantidad de contenido absurda.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (109, 4, 'Mejoraron las animaciones, pero sigue sintiéndose como el juego del año pasado.', 3, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (110, 4, 'El modo carrera tiene algunos bugs molestos que arruinan la inmersión.', 2, 'PENDIENTE');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (102, 4, 'Ideal para jugar con amigos los fines de semana, muy entretenido.', 4, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (103, 5, 'La historia es increíble y con las últimas actualizaciones funciona perfecto.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (104, 5, 'La ciudad se siente viva, pero la conducción de vehículos es terrible.', 3, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (105, 5, 'Un gran RPG de acción. La expansión mejoró muchísimo la experiencia general.', 4, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (106, 6, 'Juego infinito. Puedes construir literalmente cualquier cosa que imagines.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (107, 6, 'Muy buen juego de supervivencia, excelente para jugar en servidores con amigos.', 4, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (108, 6, 'Se vuelve un poco repetitivo si juegas solo y no tienes objetivos claros.', 3, 'PENDIENTE');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (109, 7, 'La mejor narrativa que he experimentado en un videojuego. Arthur Morgan es una leyenda.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (110, 7, 'El nivel de detalle del mundo es enfermizo. Una experiencia muy inmersiva.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (101, 7, 'El ritmo es demasiado lento para mi gusto, parece más un simulador que un juego.', 3, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (102, 8, 'Perfecto para destruir amistades. Muy divertido si juegas con chat de voz.', 4, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (103, 8, 'Los servidores públicos están llenos de gente que abandona la partida rápido.', 2, 'RECHAZADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (104, 8, 'Simple, barato y cumple su función de entretener por horas.', 4, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (105, 9, 'Las decisiones realmente importan. El nivel de rol es espectacular.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (106, 9, 'El combate por turnos es táctico y profundo, muy fiel a D&D.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (107, 9, 'El tercer acto tiene algunos problemas de rendimiento, pero es un juego sobresaliente.', 4, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (108, 10, 'El juego más relajante que existe. Ideal para desconectar después del trabajo.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (109, 10, 'Mucho contenido, secretos y cosas por hacer. Creado por una sola persona, increíble.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (110, 10, 'El combate en las minas es un poco básico, pero la gestión de la granja lo compensa.', 4, 'PENDIENTE');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (101, 11, 'Un cierre perfecto para la saga nórdica. El combate es brutal y satisfactorio.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (102, 11, 'Gráficamente es un portento, pero hay demasiados puzles interrumpiendo la acción.', 4, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (103, 11, 'La evolución de Kratos como personaje es una clase magistral de escritura.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (104, 12, 'El modo cooperativo es una genialidad. Los puzles están perfectamente diseñados.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (105, 12, 'El humor de GLaDOS y Wheatley hace que resolver acertijos sea sumamente divertido.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (106, 12, 'Me pareció muy corto, me quedé con ganas de más niveles.', 4, 'PENDIENTE');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (107, 13, 'El nuevo sistema Drive le da un dinamismo tremendo a los combates. Excelente netcode.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (108, 13, 'El modo World Tour es un buen añadido para novatos, pero se siente un poco vacío.', 3, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (109, 13, 'Los controles modernos abren la puerta a nuevos jugadores sin arruinar el competitivo.', 4, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (110, 14, 'El remake que todos queríamos. Mantiene la esencia y mejora absolutamente todo.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (101, 14, 'El sistema de apuntado es más fluido y el cuchillo añade una nueva capa táctica.', 4, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (102, 14, 'Algunos recortes respecto al original me decepcionaron un poco.', 3, 'PENDIENTE');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (103, 15, 'El clásico de estrategia que nunca envejece. La versión definitiva es fantástica.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (104, 15, 'Excelente variedad de civilizaciones y campañas históricas muy bien documentadas.', 5, 'APROBADO');
INSERT INTO resena (usuario_id, juego_id, comentario, puntuacion, estado) VALUES (105, 15, 'La curva de aprendizaje para el multijugador es altísima, pero vale la pena.', 4, 'APROBADO');